#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int data;
    struct Node* next;
} Node;

Node* newNode(int x) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->data = x;
    node->next = NULL;
    return node;
}

int detectLoop(Node* head) {
    if (!head || !head->next) return 0;
    Node *slow = head, *fast = head;
    while (fast && fast->next) {
        slow = slow->next;
        fast = fast->next->next;
        if (slow == fast) return 1;
    }
    return 0;
}

Node* createList(int arr[], int n, int pos) {
    if (n == 0) return NULL;
    Node* head = newNode(arr[0]);
    Node* curr = head;
    Node* loopNode = (pos == 1) ? head : NULL;
    for (int i = 1; i < n; ++i) {
        curr->next = newNode(arr[i]);
        curr = curr->next;
        if (i + 1 == pos) loopNode = curr; // positions are 1‑based
    }
    if (pos != 0) curr->next = loopNode;
    return head;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int arr[10000];
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        int pos; scanf("%d", &pos);
        Node* head = createList(arr, N, pos);
        printf("%s\n", detectLoop(head) ? "YES" : "NO");
        // Note: memory is not freed because the program ends quickly.
    }
    return 0;
}

