#!/usr/bin/env python3
import sys

def detect_loop(head):
    if not head or not head.next:
        return False
    slow = fast = head
    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            return True
    return False

class Node:
    __slots__ = ('data', 'next')
    def __init__(self, data):
        self.data = data
        self.next = None

def create_list(values, pos):
    if not values:
        return None
    head = Node(values[0])
    curr = head
    loop_node = head if pos == 1 else None
    for i in range(1, len(values)):
        curr.next = Node(values[i])
        curr = curr.next
        if i + 1 == pos:  # positions are 1‑based
            loop_node = curr
    if pos != 0:
        curr.next = loop_node
    return head

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        vals = [int(next(it)) for _ in range(N)]
        pos = int(next(it))
        head = create_list(vals, pos)
        out_lines.append('YES' if detect_loop(head) else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

